#!/usr/bin/env bash
# Deploy the cached card-menu + Advance modal to the Vantaca Slack bot on the VPS.
#
# WHAT THIS CHANGES (index.mjs, digest.mjs, vantaca-claude.mjs):
#   FIXED-INTENT MENU (cheap, deterministic, cached — no AI tokens):
#     - /vantaca  (no text) or "/vantaca menu" posts a Block Kit menu with:
#         • Manager queue  -> static_select of managers -> renders the SAME
#           prioritized cards as the morning digest (incl. the Advance ▸ button),
#           via vantaca_managerQueue.
#         • Aged work orders -> button -> vantaca_agedWorkOrders (portfolio, 30d+).
#         • Association status -> external_select (typeahead from
#           vantaca_associationList) -> vantaca_associationSnapshot 360 card.
#     - Each intent = one direct MCP call + a fixed renderer, with an in-memory
#       TTL cache (queue/assoc ~10m, aged ~5m). Repeat taps in-window cost
#       ZERO Claude tokens and zero MCP round-trips. Mutations are never cached.
#     - Free-text (/vantaca <question>, @mentions, DMs) still routes to the AI
#       assistant (askVantaca) as the fallback.
#   COST/CACHE:
#     - mcpTools() now sorts tools by name so the tools block is byte-stable,
#       keeping the Anthropic prompt cache (tools+system, already cache_control'd)
#       healthy across requests.
#   ADVANCE MODAL (unchanged from the prior deploy): tapping Advance ▸ opens a
#     modal showing Current step -> Moving to <next>, with an editable note field.
#
#   digest.mjs only adds `export` to itemCard (reused by the menu). No new Slack
#   scopes needed — Socket Mode already delivers block_actions + block_suggestion
#   (external_select options).
#
# Backs up all four .mjs (timestamped .bak), writes them, node --check each,
# then `systemctl restart vantaca-slack`. Safe to re-run.
#
# REQUIREMENTS (not present in the Claude-Code-on-web sandbox):
#   - ssh client + ~/.ssh/vantaca_vps private key, egress to 134.209.126.217:22
#
cd /root/vantaca-mcp/slack-bot && ts=$(date +%s) && for f in index.mjs vantaca-claude.mjs daily-report.mjs digest.mjs; do { [ -f "$f" ] && cp "$f" "$f.bak.$ts"; } || true; done && printf %s "" | base64 -d > index.mjs && printf %s "" | base64 -d > vantaca-claude.mjs && printf %s "" | base64 -d > daily-report.mjs && printf %s "" | base64 -d > digest.mjs && node --check index.mjs && node --check vantaca-claude.mjs && node --check daily-report.mjs && node --check digest.mjs && echo SYNTAX_OK && systemctl restart vantaca-slack && sleep 2 && echo "slack:$(systemctl is-active vantaca-slack)"
